        'modal.dim.mobility'  => [ 'es'=>'Movilidad','en'=>'Mobility','fr'=>'Mobilité','de'=>'Mobilität','ru'=>'Мобильность' ],
        'modal.dim.mob.desc'  => [ 'es'=>'Transporte, accesos, tiempos de desplazamiento','en'=>'Transport, access, commute times','fr'=>'Transport, accès, temps de déplacement','de'=>'Transport, Zugang, Pendelzeiten','ru'=>'Транспорт, доступ, время в пути' ],
        'modal.alicante.badge'=> [ 'es'=>'Comunidad Valenciana · Costa Mediterránea','en'=>'Valencian Community · Mediterranean Coast','fr'=>'Communauté Valencienne · Côte Méditerranéenne','de'=>'Valencianische Gemeinschaft · Mittelmeerküste','ru'=>'Сообщество Валенсии · Средиземноморское Побережье' ],
        'modal.alicante.h3'   => [ 'es'=>'El reto de la Costa Blanca','en'=>'The Costa Blanca challenge','fr'=>'Le défi de la Costa Blanca','de'=>'Die Herausforderung der Costa Blanca','ru'=>'Вызов Коста-Бланки' ],
        'modal.alicante.p1'   => [ 'es'=>'Alicante y sus municipios colindantes soportan una tremenda presión inmobiliaria. Esta entrada de capital está reconfigurando drásticamente los distritos, lo que exige auditar cada bloque: algunas zonas se han revalorizado como enclaves <em>premium</em>, mientras que otras sufren de colapso de infraestructuras por sobredensidad turística.','en'=>'Alicante and its surrounding municipalities face tremendous real estate pressure. This influx of capital is drastically reconfiguring districts, requiring an audit of every block: some areas have appreciated as <em>premium</em> enclaves, while others suffer infrastructure collapse due to tourist overdensity.','fr'=>'Alicante et ses communes voisines subissent une pression immobilière intense. Cet afflux de capital reconfigure radicalement les quartiers, exigeant un audit de chaque bloc : certaines zones se sont valorisées en enclaves <em>premium</em>, tandis que d\'autres souffrent d\'un effondrement des infrastructures lié à la surdensité touristique.','de'=>'Alicante und seine angrenzenden Gemeinden stehen unter enormem Immobiliendruck. Dieser Kapitalzufluss konfiguriert die Stadtteile drastisch um, was eine Prüfung jedes Blocks erfordert: Einige Gebiete haben sich als <em>Premium</em>-Enklaven aufgewertet, während andere unter dem Infrastrukturkollaps durch touristische Überdichte leiden.','ru'=>'Аликанте и его прилегающие муниципалитеты испытывают огромное давление на рынке недвижимости. Этот приток капитала кардинально меняет облик районов, требуя аудита каждого квартала: одни зоны выросли в цене как <em>премиальные</em> анклавы, тогда как другие страдают от коллапса инфраструктуры из-за туристической перенаселённости.' ],
        'modal.alicante.p2'   => [ 'es'=>'Al margen de plataformas genéricas, nosotros descendemos a nivel de calle para examinar la limpieza real de su futuro vecindario, el nivel acústico por la noche y quién vive en el edificio. Romvill aísla el ruido comercial para informarle con rigor sociológico.','en'=>'Beyond generic platforms, we go down to street level to examine the real cleanliness of your future neighbourhood, the noise level at night and who lives in the building. Romvill filters out commercial noise to inform you with sociological rigour.','fr'=>'Au-delà des plateformes génériques, nous descendons au niveau de la rue pour examiner la propreté réelle de votre futur quartier, le niveau sonore la nuit et qui vit dans l\'immeuble. Romvill filtre le bruit commercial pour vous informer avec rigueur sociologique.','de'=>'Jenseits generischer Plattformen gehen wir auf Straßenebene, um die tatsächliche Sauberkeit Ihrer zukünftigen Nachbarschaft, den Lärmpegel nachts und wer im Gebäude lebt zu untersuchen. Romvill filtert kommerziellen Lärm heraus, um Sie mit soziologischer Strenge zu informieren.','ru'=>'Помимо общих платформ, мы спускаемся на уровень улицы, чтобы изучить реальную чистоту вашего будущего района, уровень шума ночью и кто живёт в здании. Romvill отфильтровывает коммерческий шум, чтобы информировать вас с социологической строгостью.' ],
        'modal.alicante.cov'  => [ 'es'=>'Zona de cobertura: Alicante ciudad, El Campello, San Juan, San Vicente del Raspeig y municipios limítrofes.','en'=>'Coverage area: Alicante city, El Campello, San Juan, San Vicente del Raspeig and bordering municipalities.','fr'=>'Zone de couverture : Ville d\'Alicante, El Campello, San Juan, San Vicente del Raspeig et communes limitrophes.','de'=>'Abdeckungsgebiet: Stadt Alicante, El Campello, San Juan, San Vicente del Raspeig und angrenzende Gemeinden.','ru'=>'Зона охвата: город Аликанте, Эль-Кампельо, Сан-Хуан, Сан-Висенте-дель-Распейг и прилегающие муниципалитеты.' ],
        'modal.malaga.badge'  => [ 'es'=>'Andalucía · Costa del Sol Oriental','en'=>'Andalusia · Eastern Costa del Sol','fr'=>'Andalousie · Costa del Sol Est','de'=>'Andalusien · Östliche Costa del Sol','ru'=>'Андалусия · Восточная Коста-дель-Соль' ],
        'modal.malaga.h3'     => [ 'es'=>'Evolución y saturación tecnológica','en'=>'Evolution and technological saturation','fr'=>'Évolution et saturation technologique','de'=>'Entwicklung und technologische Sättigung','ru'=>'Эволюция и технологическое насыщение' ],
        'modal.malaga.p1'     => [ 'es'=>'Málaga se ha coronado como el equivalente europeo de <em>Silicon Valley</em>. Esta fama espectacular viene acompañada de gentrificación radical, un mercado especulativo extremadamente agresivo y una movilidad que se tensa severamente en hora punta.','en'=>'Málaga has crowned itself as Europe\'s equivalent of <em>Silicon Valley</em>. This spectacular fame comes with radical gentrification, an extremely aggressive speculative market and mobility that strains severely during peak hours.','fr'=>'Málaga s\'est couronnée comme l\'équivalent européen de la <em>Silicon Valley</em>. Cette renommée spectaculaire s\'accompagne d\'une gentrification radicale, d\'un marché spéculatif extrêmement agressif et d\'une mobilité qui se tend sévèrement aux heures de pointe.','de'=>'Málaga hat sich als europäisches Äquivalent des <em>Silicon Valley</em> etabliert. Dieser spektakuläre Ruf geht mit radikaler Gentrifizierung, einem äußerst aggressiven Spekulationsmarkt und einer Mobilität einher, die zu Stoßzeiten stark belastet wird.','ru'=>'Малага стала европейским аналогом <em>Кремниевой долины</em>. Эта громкая слава сопровождается радикальной джентрификацией, крайне агрессивным спекулятивным рынком и серьёзными транспортными перегрузками в час пик.' ],
        'modal.malaga.p2'     => [ 'es'=>'La brecha entre barrios se ha acentuado. Nuestro enfoque en el área metropolitana de Málaga y Torremolinos no obedece a folletos; rastreamos problemas de sanidad pública local, delincuencia soterrada y proyecciones urbanísticas a futuro para que actúe sobre seguro.','en'=>'The gap between neighbourhoods has widened. Our focus on the Málaga and Torremolinos metropolitan area is not based on brochures; we track local public health issues, hidden crime and future urban projections so you act with certainty.','fr'=>'L\'écart entre les quartiers s\'est accentué. Notre approche de l\'aire métropolitaine de Málaga et Torremolinos ne suit pas les brochures ; nous traquons les problèmes de santé publique locale, la délinquance souterraine et les projections urbanistiques futures pour que vous agissiez en toute sécurité.','de'=>'Die Kluft zwischen den Stadtteilen hat sich vertieft. Unser Fokus auf das Ballungsgebiet Málaga und Torremolinos basiert nicht auf Broschüren; wir verfolgen lokale öffentliche Gesundheitsprobleme, versteckte Kriminalität und zukünftige Stadtentwicklungsprojektionen, damit Sie sicher handeln.','ru'=>'Разрыв между районами усилился. Наш фокус на мегаполисе Малаги и Торремолиноса не основан на рекламных буклетах; мы отслеживаем проблемы местного общественного здравоохранения, скрытую преступность и будущие урбанистические проекты, чтобы вы действовали уверенно.' ],
        'modal.malaga.cov'    => [ 'es'=>'Zona de cobertura: Málaga capital, Torremolinos, Benalmádena, Fuengirola y el corredor de la A-7.','en'=>'Coverage area: Málaga capital, Torremolinos, Benalmádena, Fuengirola and the A-7 corridor.','fr'=>'Zone de couverture : Málaga capitale, Torremolinos, Benalmádena, Fuengirola et le corridor de l\'A-7.','de'=>'Abdeckungsgebiet: Málaga Hauptstadt, Torremolinos, Benalmádena, Fuengirola und der A-7-Korridor.','ru'=>'Зона охвата: столица Малаги, Торремолинос, Беналмадена, Фуэнхирола и коридор трассы A-7.' ],
        'modal.marbella.badge'=> [ 'es'=>'Andalucía · Costa del Sol Occidental','en'=>'Andalusia · Western Costa del Sol','fr'=>'Andalousie · Costa del Sol Ouest','de'=>'Andalusien · Westliche Costa del Sol','ru'=>'Андалусия · Западная Коста-дель-Соль' ],
        'modal.marbella.h3'   => [ 'es'=>'El espejismo del lujo','en'=>'The luxury mirage','fr'=>'Le mirage du luxe','de'=>'Die Luxusillusion','ru'=>'Мираж роскоши' ],
        'modal.marbella.p1'   => [ 'es'=>'Marbella y las zonas colindantes de alto valor (Benahavís, Sierra Blanca) albergan el mayor volumen de inversión premium de España. La extrema opacidad de su mercado local hace que evaluar la calidad interna de las urbanizaciones resulte casi imposible a la distancia.','en'=>'Marbella and surrounding high-value areas (Benahavís, Sierra Blanca) host the highest volume of premium investment in Spain. The extreme opacity of the local market makes evaluating the internal quality of developments almost impossible from a distance.','fr'=>'Marbella et les zones adjacentes de haute valeur (Benahavís, Sierra Blanca) abritent le plus grand volume d\'investissement premium d\'Espagne. L\'extrême opacité de son marché local rend presque impossible l\'évaluation de la qualité interne des urbanisations à distance.','de'=>'Marbella und die angrenzenden hochwertigen Gebiete (Benahavís, Sierra Blanca) beherbergen das höchste Premium-Investitionsvolumen Spaniens. Die extreme Undurchsichtigkeit des lokalen Marktes macht es fast unmöglich, die interne Qualität der Urbanisierungen aus der Ferne zu beurteilen.','ru'=>'Марбелья и прилегающие высококлассные районы (Беназавис, Сьерра-Бланка) сосредоточивают наибольший объём премиальных инвестиций в Испании. Крайняя непрозрачность местного рынка делает оценку внутреннего качества жилых комплексов практически невозможной на расстоянии.' ],
        'modal.marbella.p2'   => [ 'es'=>'Auditamos comunidades supuestamente idílicas para revelar su nivel de ocupación en invierno, la calidad de la conservación civil privada y, por encima de todo, los índices de seguridad activa frente a delitos silenciosos.','en'=>'We audit supposedly idyllic communities to reveal their winter occupancy level, the quality of private civil maintenance and, above all, active security indices against silent crimes.','fr'=>'Nous auditons des communautés supposément idylliques pour révéler leur niveau d\'occupation en hiver, la qualité de l\'entretien civil privé et, surtout, les indices de sécurité active face aux délits silencieux.','de'=>'Wir prüfen vermeintlich idyllische Gemeinschaften, um ihren Winterbelegungsstand, die Qualität der privaten zivilrechtlichen Erhaltung und vor allem die aktiven Sicherheitsindizes gegenüber stillen Verbrechen zu enthüllen.','ru'=>'Мы проверяем якобы идиллические жилые комплексы, чтобы выявить уровень заселённости зимой, качество частного обслуживания и, прежде всего, показатели активной безопасности в отношении скрытых преступлений.' ],
        'modal.marbella.cov'  => [ 'es'=>'Zona de cobertura: Marbella, Benahavís, Estepona, San Pedro Alcántara y la Sierra Blanca.','en'=>'Coverage area: Marbella, Benahavís, Estepona, San Pedro Alcántara and Sierra Blanca.','fr'=>'Zone de couverture : Marbella, Benahavís, Estepona, San Pedro Alcántara et la Sierra Blanca.','de'=>'Abdeckungsgebiet: Marbella, Benahavís, Estepona, San Pedro Alcántara und die Sierra Blanca.','ru'=>'Зона охвата: Марбелья, Беназавис, Эстепона, Сан-Педро-де-Алькантара и Сьерра-Бланка.' ],

