        'contact.why.title'   => [ 'es'=>'Por qué elegir Romvill','en'=>'Why choose Romvill','fr'=>'Pourquoi choisir Romvill','de'=>'Warum Romvill wählen','ru'=>'Почему выбирают Romvill' ],
        'contact.why.quote'   => [ 'es'=>'"Saber primero es siempre mejor. Romvill le da esa ventaja."','en'=>'"Knowing first is always better. Romvill gives you that advantage."','fr'=>'"Savoir en premier est toujours mieux. Romvill vous donne cet avantage."','de'=>'"Zuerst zu wissen ist immer besser. Romvill gibt Ihnen diesen Vorteil."','ru'=>'«Знать первым — всегда лучше. Romvill даёт вам это преимущество».' ],
        'contact.why.r1t'     => [ 'es'=>'Informe claro y completo','en'=>'Clear and complete report','fr'=>'Rapport clair et complet','de'=>'Klarer und vollständiger Bericht','ru'=>'Чёткий и полный отчёт' ],
        'contact.why.r1d'     => [ 'es'=>'Recibirá un informe ordenado y comprensible con todo lo que necesita saber sobre la zona que le interesa.','en'=>'You will receive an ordered, comprehensible report with everything you need to know about the area of interest.','fr'=>'Vous recevrez un rapport ordonné et compréhensible avec tout ce que vous devez savoir sur la zone qui vous intéresse.','de'=>'Sie erhalten einen geordneten, verständlichen Bericht mit allem, was Sie über das betreffende Gebiet wissen müssen.','ru'=>'Вы получите упорядоченный и понятный отчёт со всем, что нужно знать об интересующем вас районе.' ],
        'contact.why.r2t'     => [ 'es'=>'Solo analizamos, sin intereses','en'=>'We only analyse, no vested interests','fr'=>'Nous analysons uniquement, sans intérêts','de'=>'Wir analysieren nur, ohne Eigeninteressen','ru'=>'Мы только анализируем, без личных интересов' ],
        'contact.why.r2d'     => [ 'es'=>'No vendemos propiedades ni tenemos vínculos con promotores. Nuestra única función es informarle bien.','en'=>'We do not sell properties nor have ties to developers. Our only function is to inform you well.','fr'=>'Nous ne vendons pas de propriétés et n\'avons aucun lien avec des promoteurs. Notre seule fonction est de bien vous informer.','de'=>'Wir verkaufen keine Immobilien und haben keine Verbindungen zu Entwicklern. Unsere einzige Funktion ist es, Sie gut zu informieren.','ru'=>'Мы не продаём недвижимость и не связаны с застройщиками. Наша единственная функция — хорошо вас информировать.' ],
        'contact.why.r3t'     => [ 'es'=>'Datos verificados y fiables','en'=>'Verified and reliable data','fr'=>'Données vérifiées et fiables','de'=>'Verifizierte und zuverlässige Daten','ru'=>'Проверенные и надёжные данные' ],
        'contact.why.r3d'     => [ 'es'=>'Contrastamos varias fuentes para que cada dato que le damos sea real y comprobable.','en'=>'We cross-reference multiple sources so every piece of data we give you is real and verifiable.','fr'=>'Nous croisons plusieurs sources pour que chaque donnée que nous vous donnons soit réelle et vérifiable.','de'=>'Wir kreuzen mehrere Quellen, damit jede Information, die wir Ihnen geben, real und überprüfbar ist.','ru'=>'Мы перекрёстно проверяем несколько источников, чтобы каждый предоставляемый факт был реальным и проверяемым.' ],
        'contact.why.r4t'     => [ 'es'=>'Ahorro de tiempo y capital','en'=>'Time and capital savings','fr'=>'Économie de temps et de capital','de'=>'Zeit- und Kapitalersparnis','ru'=>'Экономия времени и капитала' ],
        'contact.why.r4d'     => [ 'es'=>'Evite desplazamientos innecesarios y decisiones equivocadas. Nosotros hacemos el trabajo de campo por usted.','en'=>'Avoid unnecessary travel and wrong decisions. We do the fieldwork for you.','fr'=>'Évitez les déplacements inutiles et les mauvaises décisions. Nous faisons le travail de terrain pour vous.','de'=>'Vermeiden Sie unnötige Reisen und falsche Entscheidungen. Wir erledigen die Feldarbeit für Sie.','ru'=>'Избегайте ненужных поездок и ошибочных решений. Мы выполняем полевую работу за вас.' ],
        'contact.why.r5t'     => [ 'es'=>'Confidencialidad absoluta','en'=>'Absolute confidentiality','fr'=>'Confidentialité absolue','de'=>'Absolute Vertraulichkeit','ru'=>'Абсолютная конфиденциальность' ],
        'contact.why.r5d'     => [ 'es'=>'Manejamos cada solicitud con la máxima discreción y profesionalidad.','en'=>'We handle every request with the utmost discretion and professionalism.','fr'=>'Nous traitons chaque demande avec la plus grande discrétion et professionnalisme.','de'=>'Wir bearbeiten jede Anfrage mit höchster Diskretion und Professionalität.','ru'=>'Мы обрабатываем каждый запрос с максимальной деликатностью и профессионализмом.' ],
        'contact.why.r6t'     => [ 'es'=>'Estándar Premium','en'=>'Premium Standard','fr'=>'Standard Premium','de'=>'Premium-Standard','ru'=>'Премиальный Стандарт' ],
        'contact.why.r6d'     => [ 'es'=>'Entregables de calidad ejecutiva diseñados para inversores exigentes y familias que buscan la excelencia.','en'=>'Executive-quality deliverables designed for demanding investors and families seeking excellence.','fr'=>'Livrables de qualité exécutive conçus pour des investisseurs exigeants et des familles en quête d\'excellence.','de'=>'Lieferergebnisse in Exekutivqualität für anspruchsvolle Investoren und Familien, die Exzellenz suchen.','ru'=>'Материалы исполнительного качества для взыскательных инвесторов и семей, стремящихся к совершенству.' ],
        'contact.why.r7t'     => [ 'es'=>'Alcance Internacional','en'=>'International Reach','fr'=>'Portée Internationale','de'=>'Internationale Reichweite','ru'=>'Международный Охват' ],
        'contact.why.r7d'     => [ 'es'=>'Capacidad operativa para analizar plazas en el extranjero bajo demanda.','en'=>'Operational capacity to analyse locations abroad on demand.','fr'=>'Capacité opérationnelle pour analyser des lieux à l\'étranger sur demande.','de'=>'Betriebskapazität zur Analyse von Standorten im Ausland auf Anfrage.','ru'=>'Операционный потенциал для анализа зарубежных объектов по запросу.' ],
        'contact.why.r8t'     => [ 'es'=>'Inteligencia Estratégica','en'=>'Strategic Intelligence','fr'=>'Intelligence Stratégique','de'=>'Strategische Intelligenz','ru'=>'Стратегическая Аналитика' ],
        'contact.why.r8d'     => [ 'es'=>'Convertimos los datos dispersos en decisiones claras. Minimizamos el riesgo de su inversión o traslado.','en'=>'We turn scattered data into clear decisions. We minimise the risk of your investment or relocation.','fr'=>'Nous transformons les données dispersées en décisions claires. Nous minimisons le risque de votre investissement ou déménagement.','de'=>'Wir verwandeln verstreute Daten in klare Entscheidungen. Wir minimieren das Risiko Ihrer Investition oder Ihres Umzugs.','ru'=>'Мы превращаем разрозненные данные в чёткие решения. Минимизируем риск ваших инвестиций или переезда.' ],

        // ── METODOLOGÍA PAGE ──────────────────────────────────────
        'met.badge'           => [ 'es'=>'Nuestro Proceso','en'=>'Our Process','fr'=>'Notre Processus','de'=>'Unser Prozess','ru'=>'Наш Процесс' ],
        'met.title'           => [ 'es'=>'Metodología','en'=>'Methodology','fr'=>'Méthodologie','de'=>'Methodik','ru'=>'Методология' ],
        'met.subtitle'        => [ 'es'=>'Cómo trabajamos para que usted reciba información real','en'=>'How we work so you receive real information','fr'=>'Comment nous travaillons pour que vous receviez de vraies informations','de'=>'Wie wir arbeiten, damit Sie echte Informationen erhalten','ru'=>'Как мы работаем, чтобы вы получали реальную информацию' ],
        'met.intro'           => [ 'es'=>'Así trabajamos para que usted reciba información fiable y útil: sin atajos, sin datos genéricos y con verificación directa sobre el terreno. Tres pasos claros que garantizan la calidad de cada informe que entregamos.','en'=>'This is how we work to give you reliable and useful information: no shortcuts, no generic data, and direct on-the-ground verification. Three clear steps that guarantee the quality of every report we deliver.','fr'=>'Voici comment nous travaillons pour vous fournir des informations fiables et utiles : sans raccourcis, sans données génériques et avec une vérification directe sur le terrain. Trois étapes claires qui garantissent la qualité de chaque rapport que nous livrons.','de'=>'So arbeiten wir, damit Sie zuverlässige und nützliche Informationen erhalten: ohne Abkürzungen, ohne generische Daten und mit direkter Vor-Ort-Überprüfung. Drei klare Schritte, die die Qualität jedes Berichts garantieren.','ru'=>'Вот как мы работаем, чтобы вы получали надёжную и полезную информацию: без сокращений, без общих данных и с прямой проверкой на месте. Три чётких шага, гарантирующих качество каждого отчёта.' ],
        'met.level'           => [ 'es'=>'Nivel','en'=>'Level','fr'=>'Niveau','de'=>'Ebene','ru'=>'Уровень' ],
        'met.l1.title'        => [ 'es'=>'Recolección OSINT + Campo','en'=>'OSINT + Field Collection','fr'=>'Collecte OSINT + Terrain','de'=>'OSINT + Felderhebung','ru'=>'Сбор OSINT + Полевой' ],
        'met.l1.desc'         => [ 'es'=>'Recopilamos información de <strong class="text-slate-700 dark:text-slate-200">fuentes oficiales y registros públicos</strong>, y la contrastamos con visitas presenciales sobre el terreno.','en'=>'We gather information from <strong class="text-slate-700 dark:text-slate-200">official sources and public records</strong>, cross-referencing it with on-site visits in the field.','fr'=>'Nous collectons des informations auprès de <strong class="text-slate-700 dark:text-slate-200">sources officielles et de registres publics</strong>, et les confrontons avec des visites sur le terrain.','de'=>'Wir sammeln Informationen aus <strong class="text-slate-700 dark:text-slate-200">offiziellen Quellen und öffentlichen Registern</strong> und gleichen sie mit Vor-Ort-Besuchen ab.','ru'=>'Мы собираем информацию из <strong class="text-slate-700 dark:text-slate-200">официальных источников и публичных реестров</strong> и перекрёстно проверяем её с выездными визитами.' ],
        'met.l1.i1'           => [ 'es'=>'Datos de fuentes oficiales y registros públicos','en'=>'Data from official sources and public records','fr'=>'Données de sources officielles et registres publics','de'=>'Daten aus offiziellen Quellen und öffentlichen Registern','ru'=>'Данные из официальных источников и публичных реестров' ],
        'met.l1.i2'           => [ 'es'=>'Contraste de información entre distintas fuentes','en'=>'Cross-referencing information between different sources','fr'=>'Recoupement d\'informations entre différentes sources','de'=>'Informationsabgleich zwischen verschiedenen Quellen','ru'=>'Перекрёстная проверка информации из разных источников' ],
        'met.l1.i3'           => [ 'es'=>'Equipo especializado en análisis territorial','en'=>'Team specialised in territorial analysis','fr'=>'Équipe spécialisée en analyse territoriale','de'=>'Auf Gebietsanalyse spezialisiertes Team','ru'=>'Команда, специализирующаяся на территориальном анализе' ],
        'met.l1.i4'           => [ 'es'=>'Visita presencial para confirmar lo que dicen los datos','en'=>'On-site visit to confirm what the data says','fr'=>'Visite sur site pour confirmer ce que disent les données','de'=>'Vor-Ort-Besuch zur Bestätigung der Datenlage','ru'=>'Выездной визит для подтверждения того, что говорят данные' ],
        'met.l2.title'        => [ 'es'=>'Contextualización','en'=>'Contextualisation','fr'=>'Contextualisation','de'=>'Kontextualisierung','ru'=>'Контекстуализация' ],
        'met.l2.desc'         => [ 'es'=>'Convertimos los números en algo comprensible y útil. No basta con los datos: hay que entender qué significan en la vida real de cada zona.','en'=>'We turn numbers into something comprehensible and useful. Data alone is not enough: you have to understand what it means in the real life of each area.','fr'=>'Nous transformons les chiffres en quelque chose de compréhensible et d\'utile. Les données ne suffisent pas : il faut comprendre ce qu\'elles signifient dans la vie réelle de chaque zone.','de'=>'Wir verwandeln Zahlen in etwas Verständliches und Nützliches. Daten allein reichen nicht aus: Man muss verstehen, was sie im realen Leben jeder Zone bedeuten.','ru'=>'Мы превращаем цифры во что-то понятное и полезное. Данных недостаточно: нужно понять, что они означают в реальной жизни каждой зоны.' ],
        'met.l2.i1'           => [ 'es'=>'Perfil real de quién vive en la zona','en'=>'Real profile of who lives in the area','fr'=>'Profil réel de qui vit dans la zone','de'=>'Echtes Profil der Bewohner der Zone','ru'=>'Реальный профиль жителей зоны' ],
        'met.l2.i2'           => [ 'es'=>'Nivel socioeconómico y dinámica del barrio','en'=>'Socioeconomic level and neighbourhood dynamics','fr'=>'Niveau socio-économique et dynamique du quartier','de'=>'Sozioökonomisches Niveau und Quartiersdynamik','ru'=>'Социально-экономический уровень и динамика района' ],
        'met.l2.i3'           => [ 'es'=>'Calidad de vida y percepción del entorno','en'=>'Quality of life and perception of the environment','fr'=>'Qualité de vie et perception de l\'environnement','de'=>'Lebensqualität und Wahrnehmung der Umgebung','ru'=>'Качество жизни и восприятие окружающей среды' ],
        'met.l2.i4'           => [ 'es'=>'Contexto regional y comparativa con zonas similares','en'=>'Regional context and comparison with similar areas','fr'=>'Contexte régional et comparaison avec des zones similaires','de'=>'Regionaler Kontext und Vergleich mit ähnlichen Zonen','ru'=>'Региональный контекст и сравнение с аналогичными зонами' ],
        'met.l2.i5'           => [ 'es'=>'Seguridad percibida y ambiente real del área','en'=>'Perceived security and real atmosphere of the area','fr'=>'Sécurité perçue et atmosphère réelle de la zone','de'=>'Wahrgenommene Sicherheit und echte Atmosphäre des Bereichs','ru'=>'Воспринимаемая безопасность и реальная атмосфера района' ],
        'met.l3.title'        => [ 'es'=>'Presentación','en'=>'Presentation','fr'=>'Présentation','de'=>'Präsentation','ru'=>'Презентация' ],
        'met.l3.desc'         => [ 'es'=>'Todo lo analizado se resume en un informe claro y ordenado, entregado en el plazo acordado. Sin tecnicismos innecesarios.','en'=>'Everything analysed is summarised in a clear and ordered report, delivered within the agreed timeframe. No unnecessary jargon.','fr'=>'Tout ce qui a été analysé est résumé dans un rapport clair et ordonné, livré dans le délai convenu. Sans jargon inutile.','de'=>'Alles Analysierte wird in einem klaren und geordneten Bericht zusammengefasst, der innerhalb der vereinbarten Frist geliefert wird. Ohne unnötigen Fachjargon.','ru'=>'Всё проанализированное резюмируется в чётком и упорядоченном отчёте, доставляемом в согласованные сроки. Без лишнего жаргона.' ],
        'met.l3.i1'           => [ 'es'=>'Informe estructurado y fácil de entender','en'=>'Structured and easy-to-understand report','fr'=>'Rapport structuré et facile à comprendre','de'=>'Strukturierter und leicht verständlicher Bericht','ru'=>'Структурированный и понятный отчёт' ],
        'met.l3.i2'           => [ 'es'=>'Resumen ejecutivo con los puntos clave','en'=>'Executive summary with key points','fr'=>'Résumé exécutif avec les points clés','de'=>'Zusammenfassung für Führungskräfte mit wichtigen Punkten','ru'=>'Резюме для руководства с ключевыми пунктами' ],
        'met.l3.i3'           => [ 'es'=>'Comparativa entre zonas si fuera necesario','en'=>'Zone comparison if required','fr'=>'Comparaison entre zones si nécessaire','de'=>'Zonenvergleich falls erforderlich','ru'=>'Сравнение зон при необходимости' ],
        'met.l3.i4'           => [ 'es'=>'Conclusiones claras y directas','en'=>'Clear and direct conclusions','fr'=>'Conclusions claires et directes','de'=>'Klare und direkte Schlussfolgerungen','ru'=>'Чёткие и прямые выводы' ],
        'met.l3.i5'           => [ 'es'=>'Dossier completo entregado en el plazo acordado','en'=>'Complete dossier delivered within the agreed timeframe','fr'=>'Dossier complet livré dans le délai convenu','de'=>'Vollständiges Dossier innerhalb der vereinbarten Frist','ru'=>'Полный досье, доставленный в согласованные сроки' ],
        'met.filter.badge'    => [ 'es'=>'Filtro Romvill','en'=>'Romvill Filter','fr'=>'Filtre Romvill','de'=>'Romvill-Filter','ru'=>'Фильтр Romvill' ],
        'met.filter.title'    => [ 'es'=>'Convertimos datos dispersos en <span class="italic text-slate-400">criterio estratégico</span>','en'=>'We turn scattered data into <span class="italic text-slate-400">strategic insight</span>','fr'=>'Nous transformons les données dispersées en <span class="italic text-slate-400">critère stratégique</span>','de'=>'Wir verwandeln verstreute Daten in <span class="italic text-slate-400">strategisches Urteil</span>','ru'=>'Мы превращаем разрозненные данные в <span class="italic text-slate-400">стратегическое понимание</span>' ],
        'met.filter.desc'     => [ 'es'=>'En el mercado actual, el problema no es la falta de información, sino el exceso de datos irrelevantes o sesgados. Nuestro trabajo es actuar como su analista experto.','en'=>'In today\'s market, the problem is not a lack of information, but an excess of irrelevant or biased data. Our job is to act as your expert analyst.','fr'=>'Dans le marché actuel, le problème n\'est pas le manque d\'information, mais l\'excès de données non pertinentes ou biaisées. Notre travail est d\'agir en tant qu\'analyste expert.','de'=>'Im heutigen Markt ist das Problem nicht der Mangel an Informationen, sondern der Überschuss an irrelevanten oder voreingenommenen Daten. Unsere Aufgabe ist es, als Ihr Expertenanalyst zu fungieren.','ru'=>'На сегодняшнем рынке проблема не в нехватке информации, а в избытке нерелевантных или предвзятых данных. Наша задача — выступать вашим экспертным аналитиком.' ],
        'met.b1.title'        => [ 'es'=>'Cero Especulación','en'=>'Zero Speculation','fr'=>'Zéro Spéculation','de'=>'Null Spekulation','ru'=>'Ноль Спекуляций' ],
        'met.b1.desc'         => [ 'es'=>'Eliminamos el "me han dicho" y el "parece que". Todo lo que incluimos en el informe ha sido validado.','en'=>'We eliminate "I heard" and "it seems". Everything included in the report has been validated.','fr'=>'Nous éliminons le "on m\'a dit" et le "il semble que". Tout ce qui est inclus dans le rapport a été validé.','de'=>'Wir eliminieren das "Man hat mir gesagt" und das "Es scheint". Alles im Bericht ist validiert.','ru'=>'Мы устраняем «мне говорили» и «кажется». Всё, что включено в отчёт, прошло проверку.' ],
        'met.b2.title'        => [ 'es'=>'Trabajo de Campo Real','en'=>'Real Fieldwork','fr'=>'Travail de Terrain Réel','de'=>'Echte Feldarbeit','ru'=>'Реальная Полевая Работа' ],
        'met.b2.desc'         => [ 'es'=>'Los satélites no cuentan toda la historia. Pisamos el terreno, medimos los tiempos de acceso.','en'=>'Satellites do not tell the whole story. We walk the ground, we measure access times.','fr'=>'Les satellites ne racontent pas toute l\'histoire. Nous foulons le terrain, mesurons les temps d\'accès.','de'=>'Satelliten erzählen nicht die ganze Geschichte. Wir betreten das Gelände und messen die Zugangszeiten.','ru'=>'Спутники не рассказывают всей истории. Мы ходим по земле, измеряем время в пути.' ],
        'met.b3.title'        => [ 'es'=>'Perspectiva Independiente','en'=>'Independent Perspective','fr'=>'Perspective Indépendante','de'=>'Unabhängige Perspektive','ru'=>'Независимая Перспектива' ],
        'met.b3.desc'         => [ 'es'=>'No intermediamos en operaciones ni promocionamos zonas. Nuestro único objetivo es la radiografía exacta del lugar.','en'=>'We do not broker deals or promote areas. Our only objective is the exact X-ray of the location.','fr'=>'Nous n\'intermédiaire pas dans des opérations et ne promouvons pas des zones. Notre seul objectif est la radiographie exacte du lieu.','de'=>'Wir vermitteln keine Geschäfte und fördern keine Zonen. Unser einziges Ziel ist das genaue Röntgenbild des Ortes.','ru'=>'Мы не посредничаем в сделках и не продвигаем зоны. Наша единственная цель — точный «рентгеновский снимок» места.' ],
        'met.card1.title'     => [ 'es'=>'Validación Múltiple','en'=>'Multiple Validation','fr'=>'Validation Multiple','de'=>'Mehrfachvalidierung','ru'=>'Многократная Валидация' ],
        'met.card1.desc'      => [ 'es'=>'Cruzamos hasta 5 fuentes de datos por dimensión analizada.','en'=>'We cross up to 5 data sources per analysed dimension.','fr'=>'Nous croisons jusqu\'à 5 sources de données par dimension analysée.','de'=>'Wir kreuzen bis zu 5 Datenquellen pro analysierter Dimension.','ru'=>'Мы перекрёстно проверяем до 5 источников данных на каждое анализируемое измерение.' ],
        'met.card2.title'     => [ 'es'=>'Escaneo de Riesgos','en'=>'Risk Scanning','fr'=>'Analyse des Risques','de'=>'Risikoanalyse','ru'=>'Сканирование Рисков' ],
        'met.card2.desc'      => [ 'es'=>'Identificamos los puntos ciegos, como tasas de criminalidad ocultas.','en'=>'We identify blind spots, such as hidden crime rates.','fr'=>'Nous identifions les angles morts, comme les taux de criminalité cachés.','de'=>'Wir identifizieren blinde Flecken, wie versteckte Kriminalitätsraten.','ru'=>'Мы выявляем слепые зоны, такие как скрытые показатели преступности.' ],
        'met.card3.title'     => [ 'es'=>'Visión de Oportunidad','en'=>'Opportunity Vision','fr'=>'Vision d\'Opportunité','de'=>'Chancenblick','ru'=>'Видение Возможностей' ],
        'met.card3.desc'      => [ 'es'=>'Nuestros perfiles proyectan el valor a futuro: detectando posibles gentrificaciones y grandes proyectos urbanos.','en'=>'Our profiles project future value: detecting possible gentrification and major urban projects.','fr'=>'Nos profils projettent la valeur future : détectant les gentrifications possibles et les grands projets urbains.','de'=>'Unsere Profile projizieren den zukünftigen Wert: Sie erkennen mögliche Gentrifizierungen und große Stadtentwicklungsprojekte.','ru'=>'Наши профили проецируют будущую ценность: выявляя возможную джентрификацию и крупные городские проекты.' ],
        'met.obj_badge'       => [ 'es'=>'Objetividad','en'=>'Objectivity','fr'=>'Objectivité','de'=>'Objektivität','ru'=>'Объективность' ],
        'met.cta.title'       => [ 'es'=>'¿Tiene preguntas sobre cómo trabajamos?','en'=>'Do you have questions about how we work?','fr'=>'Avez-vous des questions sur notre façon de travailler ?','de'=>'Haben Sie Fragen zu unserer Arbeitsweise?','ru'=>'Есть ли у вас вопросы о том, как мы работаем?' ],
        'met.cta.desc'        => [ 'es'=>'Si quiere saber más sobre cómo elaboramos los informes o tiene preguntas concretas sobre su caso, estamos para ayudarle.','en'=>'If you want to know more about how we prepare the reports or have specific questions about your case, we are here to help.','fr'=>'Si vous souhaitez en savoir plus sur la façon dont nous élaborons les rapports ou si vous avez des questions précises sur votre cas, nous sommes là pour vous aider.','de'=>'Wenn Sie mehr darüber erfahren möchten, wie wir die Berichte erstellen, oder konkrete Fragen zu Ihrem Fall haben, sind wir hier, um zu helfen.','ru'=>'Если вы хотите узнать больше о том, как мы готовим отчёты, или у вас есть конкретные вопросы о вашем случае — мы здесь, чтобы помочь.' ],
        'met.cta.btn'         => [ 'es'=>'Hablar con nosotros','en'=>'Talk to us','fr'=>'Parler avec nous','de'=>'Mit uns sprechen','ru'=>'Поговорить с нами' ],

        // ── ANÁLISIS PAGE ─────────────────────────────────────────
        'ana.badge'           => [ 'es'=>'Inteligencia Territorial','en'=>'Territorial Intelligence','fr'=>'Intelligence Territoriale','de'=>'Territoriale Intelligenz','ru'=>'Территориальная Аналитика' ],
        'ana.title'           => [ 'es'=>'Lo que analizamos <br class="hidden sm:block" /><span class="text-transparent bg-clip-text bg-gradient-to-r from-primary to-blue-400">para que usted decida con seguridad</span>','en'=>'What we analyse <br class="hidden sm:block" /><span class="text-transparent bg-clip-text bg-gradient-to-r from-primary to-blue-400">so you decide with confidence</span>','fr'=>'Ce que nous analysons <br class="hidden sm:block" /><span class="text-transparent bg-clip-text bg-gradient-to-r from-primary to-blue-400">pour que vous décidiez en toute sécurité</span>','de'=>'Was wir analysieren <br class="hidden sm:block" /><span class="text-transparent bg-clip-text bg-gradient-to-r from-primary to-blue-400">damit Sie sicher entscheiden</span>','ru'=>'Что мы анализируем <br class="hidden sm:block" /><span class="text-transparent bg-clip-text bg-gradient-to-r from-primary to-blue-400">чтобы вы решали уверенно</span>' ],
        'ana.desc'            => [ 'es'=>'Antes de mudarse o dar cualquier paso importante, Romvill estudia a fondo la zona que le interesa: seguridad real, quién vive allí, qué servicios tiene y cómo es moverse por esa área.','en'=>'Before moving or taking any important step, Romvill thoroughly studies the area that interests you: real security, who lives there, what services it has and what it is like to get around that area.','fr'=>'Avant de déménager ou de prendre tout pas important, Romvill étudie en profondeur la zone qui vous intéresse : sécurité réelle, qui y vit, quels services elle offre et comment se déplacer dans cette zone.','de'=>'Bevor Sie umziehen oder einen wichtigen Schritt unternehmen, untersucht Romvill gründlich die Zone, die Sie interessiert: echte Sicherheit, wer dort lebt, welche Dienstleistungen es hat und wie es ist, sich in diesem Gebiet zu bewegen.','ru'=>'Прежде чем переехать или сделать важный шаг, Romvill тщательно изучает интересующую вас зону: реальная безопасность, кто там живёт, какие есть услуги и как передвигаться по этому району.' ],
        'ana.d1.title'        => [ 'es'=>'Seguridad Real de la Zona','en'=>'Real Security of the Area','fr'=>'Sécurité Réelle de la Zone','de'=>'Echte Sicherheit der Zone','ru'=>'Реальная Безопасность Зоны' ],
        'ana.d1.desc'         => [ 'es'=>'No nos basamos en rumores ni en apariencias. Analizamos la seguridad de un área integrando datos oficiales de criminalidad y comprobando in situ el ambiente real.','en'=>'We do not rely on rumours or appearances. We analyse the security of an area by integrating official crime data and verifying the real atmosphere on-site.','fr'=>'Nous ne nous basons pas sur des rumeurs ou des apparences. Nous analysons la sécurité d\'une zone en intégrant les données officielles de criminalité et en vérifiant sur place l\'atmosphère réelle.','de'=>'Wir verlassen uns nicht auf Gerüchte oder Erscheinungen. Wir analysieren die Sicherheit eines Gebiets, indem wir offizielle Kriminalitätsdaten integrieren und die tatsächliche Atmosphäre vor Ort prüfen.','ru'=>'Мы не полагаемся на слухи или внешний вид. Мы анализируем безопасность района, интегрируя официальные данные о преступности и проверяя реальную атмосферу на месте.' ],
        'ana.d1.i1'           => [ 'es'=>'Estadísticas oficiales contrastadas','en'=>'Cross-referenced official statistics','fr'=>'Statistiques officielles recoupées','de'=>'Abgeglichene offizielle Statistiken','ru'=>'Перекрёстно проверенные официальные статистики' ],
        'ana.d1.i2'           => [ 'es'=>'Evaluación de conflictividad vecinal','en'=>'Assessment of neighbourhood conflict','fr'=>'Évaluation de la conflictualité de voisinage','de'=>'Bewertung von Nachbarschaftskonflikten','ru'=>'Оценка конфликтности в районе' ],
        'ana.d1.link'         => [ 'es'=>'Ver Perfil de Seguridad','en'=>'See Security Profile','fr'=>'Voir Profil de Sécurité','de'=>'Sicherheitsprofil ansehen','ru'=>'Просмотреть Профиль Безопасности' ],
        'ana.d2.title'        => [ 'es'=>'Perfil Demográfico','en'=>'Demographic Profile','fr'=>'Profil Démographique','de'=>'Demografisches Profil','ru'=>'Демографический Профиль' ],
        'ana.d2.desc'         => [ 'es'=>'Conocer a sus futuros vecinos o el público de su inversión es vital. Elaboramos una radiografía precisa de quién habita la zona.','en'=>'Knowing your future neighbours or the audience for your investment is vital. We draw up a precise X-ray of who inhabits the area.','fr'=>'Connaître vos futurs voisins ou le public de votre investissement est vital. Nous établissons une radiographie précise de qui habite la zone.','de'=>'Ihre zukünftigen Nachbarn oder das Publikum Ihrer Investition zu kennen ist entscheidend. Wir erstellen ein genaues Röntgenbild der Bewohner des Gebiets.','ru'=>'Знать своих будущих соседей или аудиторию вашей инвестиции жизненно важно. Мы составляем точный «рентгеновский снимок» того, кто населяет зону.' ],
        'ana.d2.i1'           => [ 'es'=>'Composición familiar y edad media','en'=>'Family composition and average age','fr'=>'Composition familiale et âge moyen','de'=>'Familienzusammensetzung und Durchschnittsalter','ru'=>'Состав семей и средний возраст' ],
        'ana.d2.i2'           => [ 'es'=>'Evolución de la población local','en'=>'Evolution of the local population','fr'=>'Évolution de la population locale','de'=>'Entwicklung der lokalen Bevölkerung','ru'=>'Динамика местного населения' ],
        'ana.d2.link'         => [ 'es'=>'Ver Perfil Demográfico','en'=>'See Demographic Profile','fr'=>'Voir Profil Démographique','de'=>'Demografisches Profil ansehen','ru'=>'Просмотреть Демографический Профиль' ],
        'ana.d3.title'        => [ 'es'=>'Cobertura Sanitaria','en'=>'Healthcare Coverage','fr'=>'Couverture Sanitaire','de'=>'Gesundheitsversorgung','ru'=>'Охват Здравоохранения' ],
        'ana.d3.desc'         => [ 'es'=>'La salud y las emergencias no pueden depender del azar. Mapeamos la disponibilidad y calidad de los servicios médicos cercanos.','en'=>'Health and emergencies cannot depend on chance. We map the availability and quality of nearby medical services.','fr'=>'La santé et les urgences ne peuvent pas dépendre du hasard. Nous cartographions la disponibilité et la qualité des services médicaux proches.','de'=>'Gesundheit und Notfälle können nicht vom Zufall abhängen. Wir kartieren die Verfügbarkeit und Qualität nahegelegener medizinischer Dienste.','ru'=>'Здоровье и экстренные ситуации не могут зависеть от случая. Мы составляем карту доступности и качества ближайших медицинских услуг.' ],
        'ana.d3.i1'           => [ 'es'=>'Infraestructura pública y privada','en'=>'Public and private infrastructure','fr'=>'Infrastructure publique et privée','de'=>'Öffentliche und private Infrastruktur','ru'=>'Государственная и частная инфраструктура' ],
        'ana.d3.i2'           => [ 'es'=>'Distancias clínicas y accesibilidad','en'=>'Clinical distances and accessibility','fr'=>'Distances cliniques et accessibilité','de'=>'Klinische Entfernungen und Zugänglichkeit','ru'=>'Расстояния до клиник и доступность' ],
        'ana.d3.link'         => [ 'es'=>'Ver Perfil de Sanidad','en'=>'See Healthcare Profile','fr'=>'Voir Profil de Santé','de'=>'Gesundheitsprofil ansehen','ru'=>'Просмотреть Профиль Здравоохранения' ],
        'ana.d4.title'        => [ 'es'=>'Conectividad y Movilidad','en'=>'Connectivity and Mobility','fr'=>'Connectivité et Mobilité','de'=>'Konnektivität und Mobilität','ru'=>'Связность и Мобильность' ],
        'ana.d4.desc'         => [ 'es'=>'El tiempo es oro. Estudiamos las arterias de la zona: accesos por carretera, tráfico real en horas punta, opciones de transporte público.','en'=>'Time is gold. We study the arteries of the area: road accesses, real peak-hour traffic, public transport options.','fr'=>'Le temps c\'est de l\'or. Nous étudions les artères de la zone : accès routiers, trafic réel aux heures de pointe, options de transport en commun.','de'=>'Zeit ist Gold. Wir untersuchen die Adern der Zone: Straßenzugänge, realer Stoßzeitverkehr, Optionen des öffentlichen Verkehrs.','ru'=>'Время — золото. Мы изучаем артерии зоны: дорожные подъезды, реальный трафик в час пик, варианты общественного транспорта.' ],
        'ana.d4.i1'           => [ 'es'=>'Nudos de transporte y aparcamiento','en'=>'Transport hubs and parking','fr'=>'Noeuds de transport et stationnement','de'=>'Verkehrsknotenpunkte und Parken','ru'=>'Транспортные узлы и парковка' ],
        'ana.d4.i2'           => [ 'es'=>'Nivel de congestión residencial','en'=>'Residential congestion level','fr'=>'Niveau de congestion résidentielle','de'=>'Residentielles Stauniveau','ru'=>'Уровень жилой загруженности' ],
        'ana.d4.link'         => [ 'es'=>'Ver Perfil de Movilidad','en'=>'See Mobility Profile','fr'=>'Voir Profil de Mobilité','de'=>'Mobilitätsprofil ansehen','ru'=>'Просмотреть Профиль Мобильности' ],
        'ana.dim'             => [ 'es'=>'Dimensión','en'=>'Dimension','fr'=>'Dimension','de'=>'Dimension','ru'=>'Измерение' ],
        'ana.cta.title'       => [ 'es'=>'Un informe hecho para usted','en'=>'A report made for you','fr'=>'Un rapport fait pour vous','de'=>'Ein Bericht für Sie gemacht','ru'=>'Отчёт, сделанный для вас' ],
        'ana.cta.desc'        => [ 'es'=>'Nuestros informes no son genéricos. Combinamos estas dimensiones de análisis para crear un perfil completo de la zona.','en'=>'Our reports are not generic. We combine these analytical dimensions to create a complete profile of the area.','fr'=>'Nos rapports ne sont pas génériques. Nous combinons ces dimensions d\'analyse pour créer un profil complet de la zone.','de'=>'Unsere Berichte sind nicht generisch. Wir kombinieren diese analytischen Dimensionen, um ein vollständiges Profil der Zone zu erstellen.','ru'=>'Наши отчёты не являются общими. Мы объединяем эти аналитические измерения для создания полного профиля зоны.' ],
        'ana.cta.btn'         => [ 'es'=>'Solicitar Informe','en'=>'Request Report','fr'=>'Demander le Rapport','de'=>'Bericht Anfordern','ru'=>'Запросить Отчёт' ],

        // ── SECTORES PAGE ─────────────────────────────────────────
        'sec.b2c.title'       => [ 'es'=>'Para Particulares <br />y Familias','en'=>'For Individuals <br />and Families','fr'=>'Pour les Particuliers <br />et les Familles','de'=>'Für Privatpersonen <br />und Familien','ru'=>'Для Физических Лиц <br />и Семей' ],
        'sec.b2c.desc'        => [ 'es'=>'Le damos información real sobre la zona donde va a vivir: seguridad, servicios, entorno y todo lo que importa.','en'=>'We give you real information about the area where you are going to live: security, services, environment and everything that matters.','fr'=>'Nous vous donnons de vraies informations sur la zone où vous allez vivre : sécurité, services, environnement et tout ce qui compte.','de'=>'Wir geben Ihnen echte Informationen über die Zone, in der Sie leben werden: Sicherheit, Dienstleistungen, Umgebung und alles, was wichtig ist.','ru'=>'Мы предоставляем реальную информацию о районе, где вы будете жить: безопасность, услуги, окружение и всё важное.' ],
        'sec.b2c.btn'         => [ 'es'=>'Estudio Residencial','en'=>'Residential Study','fr'=>'Étude Résidentielle','de'=>'Wohnstudie','ru'=>'Жилищное Исследование' ],
        'sec.b2b.title'       => [ 'es'=>'Para Inversores <br />y Empresas','en'=>'For Investors <br />and Companies','fr'=>'Pour les Investisseurs <br />et les Entreprises','de'=>'Für Investoren <br />und Unternehmen','ru'=>'Для Инвесторов <br />и Компаний' ],
        'sec.b2b.desc'        => [ 'es'=>'Información territorial detallada y análisis de zona para que tome decisiones fundamentadas.','en'=>'Detailed territorial information and area analysis so you make informed decisions.','fr'=>'Informations territoriales détaillées et analyse de zone pour que vous preniez des décisions éclairées.','de'=>'Detaillierte territoriale Informationen und Zonenanalyse für fundierte Entscheidungen.','ru'=>'Подробная территориальная информация и анализ зоны для принятия обоснованных решений.' ],
        'sec.cover.badge'     => [ 'es'=>'Áreas de Cobertura','en'=>'Coverage Areas','fr'=>'Zones de Couverture','de'=>'Abdeckungsgebiete','ru'=>'Зоны Охвата' ],
        'sec.cover.title'     => [ 'es'=>'Dónde Operamos','en'=>'Where We Operate','fr'=>'Où Nous Opérons','de'=>'Wo Wir Tätig Sind','ru'=>'Где Мы Работаем' ],
        'sec.cover.desc'      => [ 'es'=>'Nuestra actividad se concentra en las tres áreas más exclusivas y demandadas de la costa mediterránea.','en'=>'Our activity is concentrated in the three most exclusive and sought-after areas on the Mediterranean coast.','fr'=>'Notre activité se concentre dans les trois zones les plus exclusives et les plus demandées de la côte méditerranéenne.','de'=>'Unsere Aktivität konzentriert sich auf die drei exklusivsten und begehrtesten Gebiete der Mittelmeerküste.','ru'=>'Наша деятельность сосредоточена в трёх наиболее эксклюзивных и востребованных районах средиземноморского побережья.' ],
        'sec.alicante.sub'    => [ 'es'=>'Costa Blanca','en'=>'Costa Blanca','fr'=>'Costa Blanca','de'=>'Costa Blanca','ru'=>'Коста-Бланка' ],
        'sec.marbella.sub'    => [ 'es'=>'Costa del Sol','en'=>'Costa del Sol','fr'=>'Costa del Sol','de'=>'Costa del Sol','ru'=>'Коста-дель-Соль' ],
        'sec.malaga.sub'      => [ 'es'=>'Capital de la Costa','en'=>'Coast Capital','fr'=>'Capitale de la Côte','de'=>'Hauptstadt der Küste','ru'=>'Столица Побережья' ],
        'sec.intl.title'      => [ 'es'=>'Servicios Internacionales y Otras Ciudades','en'=>'International Services and Other Cities','fr'=>'Services Internationaux et Autres Villes','de'=>'Internationale Dienste und Andere Städte','ru'=>'Международные Услуги и Другие Города' ],
        'sec.intl.desc'       => [ 'es'=>'De forma excepcional, realizamos informes territoriales en <strong>el extranjero y en otras ciudades</strong> bajo demanda. Los costes requerirán un presupuesto personalizado.','en'=>'On an exceptional basis, we carry out territorial reports <strong>abroad and in other cities</strong> on demand. Costs will require a personalised quote.','fr'=>'À titre exceptionnel, nous réalisons des rapports territoriaux <strong>à l\'étranger et dans d\'autres villes</strong> sur demande. Les coûts nécessiteront un devis personnalisé.','de'=>'Auf außerordentlicher Basis führen wir territoriale Berichte <strong>im Ausland und in anderen Städten</strong> auf Anfrage durch. Die Kosten erfordern ein individuelles Angebot.','ru'=>'В исключительных случаях мы проводим территориальные исследования <strong>за рубежом и в других городах</strong> по запросу. Стоимость потребует индивидуального предложения.' ],
        'sec.intl.link'       => [ 'es'=>'Consultar disponibilidad','en'=>'Check availability','fr'=>'Vérifier la disponibilité','de'=>'Verfügbarkeit prüfen','ru'=>'Проверить доступность' ],
        'sec.spec.badge'      => [ 'es'=>'Servicios Especializados','en'=>'Specialised Services','fr'=>'Services Spécialisés','de'=>'Spezialisierte Dienste','ru'=>'Специализированные Услуги' ],
        'sec.spec.title'      => [ 'es'=>'Análisis para cada caso','en'=>'Analysis for every case','fr'=>'Analyse pour chaque cas','de'=>'Analyse für jeden Fall','ru'=>'Анализ для каждого случая' ],
        'sec.spec.desc'       => [ 'es'=>'Trabajamos tanto con personas y familias que van a vivir en la zona, como con inversores que necesitan conocerla antes de actuar.','en'=>'We work with both individuals and families who are going to live in the area, and investors who need to know it before acting.','fr'=>'Nous travaillons avec des personnes et des familles qui vont vivre dans la zone, ainsi qu\'avec des investisseurs qui ont besoin de la connaître avant d\'agir.','de'=>'Wir arbeiten sowohl mit Personen und Familien, die in der Zone leben werden, als auch mit Investoren, die sie kennen müssen, bevor sie handeln.','ru'=>'Мы работаем как с физическими лицами и семьями, которые собираются жить в этом районе, так и с инвесторами, которым необходимо знать его перед принятием решения.' ],
        'sec.res.badge'       => [ 'es'=>'Seguridad Residencial','en'=>'Residential Security','fr'=>'Sécurité Résidentielle','de'=>'Wohnsicherheit','ru'=>'Жилая Безопасность' ],
        'sec.res.title'       => [ 'es'=>'Particulares y Familias','en'=>'Individuals and Families','fr'=>'Particuliers et Familles','de'=>'Privatpersonen und Familien','ru'=>'Физические Лица и Семьи' ],
        'sec.res.desc'        => [ 'es'=>'Le decimos si la zona donde quiere vivir es <strong class="text-slate-900 dark:text-white">segura, bien equipada y rentable</strong> a largo plazo.','en'=>'We tell you whether the area where you want to live is <strong class="text-slate-900 dark:text-white">safe, well-equipped and worthwhile</strong> in the long term.','fr'=>'Nous vous disons si la zone où vous souhaitez vivre est <strong class="text-slate-900 dark:text-white">sûre, bien équipée et rentable</strong> à long terme.','de'=>'Wir sagen Ihnen, ob die Zone, in der Sie leben möchten, <strong class="text-slate-900 dark:text-white">sicher, gut ausgestattet und lohnend</strong> ist.','ru'=>'Мы скажем вам, является ли район, в котором вы хотите жить, <strong class="text-slate-900 dark:text-white">безопасным, хорошо оснащённым и перспективным</strong> в долгосрочной перспективе.' ],
        'sec.r1t'             => [ 'es'=>'Seguridad real del barrio','en'=>'Real neighbourhood security','fr'=>'Sécurité réelle du quartier','de'=>'Echte Sicherheit des Viertels','ru'=>'Реальная безопасность района' ],
        'sec.r1d'             => [ 'es'=>'Incidentes, tendencias y comparativa con zonas similares.','en'=>'Incidents, trends and comparison with similar areas.','fr'=>'Incidents, tendances et comparaison avec des zones similaires.','de'=>'Vorfälle, Trends und Vergleich mit ähnlichen Zonen.','ru'=>'Инциденты, тенденции и сравнение с аналогичными зонами.' ],
        'sec.r2t'             => [ 'es'=>'Servicios esenciales cercanos','en'=>'Nearby essential services','fr'=>'Services essentiels proches','de'=>'Nahe wesentliche Dienstleistungen','ru'=>'Ближайшие основные услуги' ],
        'sec.r2d'             => [ 'es'=>'Colegios, centros de salud, comercios y ocio.','en'=>'Schools, health centres, shops and leisure.','fr'=>'Écoles, centres de santé, commerces et loisirs.','de'=>'Schulen, Gesundheitszentren, Geschäfte und Freizeit.','ru'=>'Школы, медицинские центры, магазины и досуг.' ],
        'sec.r3t'             => [ 'es'=>'Entorno y calidad de vida','en'=>'Environment and quality of life','fr'=>'Environnement et qualité de vie','de'=>'Umgebung und Lebensqualität','ru'=>'Окружение и качество жизни' ],
        'sec.r3d'             => [ 'es'=>'Cómo es el día a día: tranquilidad, ambiente, ruido.','en'=>'What daily life is like: calm, atmosphere, noise.','fr'=>'À quoi ressemble le quotidien : tranquillité, ambiance, bruit.','de'=>'Wie der Alltag ist: Ruhe, Atmosphäre, Lärm.','ru'=>'Каков повседневный уклад: спокойствие, атмосфера, шум.' ],
        'sec.r4t'             => [ 'es'=>'Perfil del vecindario','en'=>'Neighbourhood profile','fr'=>'Profil du voisinage','de'=>'Nachbarschaftsprofil','ru'=>'Профиль района' ],
        'sec.r4d'             => [ 'es'=>'Quiénes viven allí, nivel de vida y dinámica social.','en'=>'Who lives there, standard of living and social dynamics.','fr'=>'Qui y vit, niveau de vie et dynamique sociale.','de'=>'Wer dort lebt, Lebensstandard und soziale Dynamik.','ru'=>'Кто там живёт, уровень жизни и социальная динамика.' ],
        'sec.res.link'        => [ 'es'=>'Solicitar informe residencial','en'=>'Request residential report','fr'=>'Demander un rapport résidentiel','de'=>'Wohnbericht anfordern','ru'=>'Запросить жилищный отчёт' ],
        'sec.inv.badge'       => [ 'es'=>'Inteligencia Territorial','en'=>'Territorial Intelligence','fr'=>'Intelligence Territoriale','de'=>'Territoriale Intelligenz','ru'=>'Территориальная Аналитика' ],
        'sec.inv.title'       => [ 'es'=>'Inversores y Empresas','en'=>'Investors and Companies','fr'=>'Investisseurs et Entreprises','de'=>'Investoren und Unternehmen','ru'=>'Инвесторы и Компании' ],
        'sec.inv.desc'        => [ 'es'=>'Antes de comprometerse, conozca a fondo la zona: <strong class="text-white">quién la habita, qué infraestructura tiene y qué dice la normativa</strong>.','en'=>'Before committing, know the area thoroughly: <strong class="text-white">who inhabits it, what infrastructure it has and what the regulations say</strong>.','fr'=>'Avant de vous engager, connaissez la zone en profondeur : <strong class="text-white">qui l\'habite, quelle infrastructure elle possède et ce que dit la réglementation</strong>.','de'=>'Bevor Sie sich verpflichten, kennen Sie die Zone gründlich: <strong class="text-white">wer sie bewohnt, welche Infrastruktur sie hat und was die Vorschriften sagen</strong>.','ru'=>'Прежде чем брать обязательства, досконально изучите район: <strong class="text-white">кто его населяет, какова инфраструктура и что говорит законодательство</strong>.' ],
        'sec.i1t'             => [ 'es'=>'Comparativa objetiva de zonas','en'=>'Objective zone comparison','fr'=>'Comparaison objective des zones','de'=>'Objektiver Zonenvergleich','ru'=>'Объективное сравнение зон' ],
        'sec.i1d'             => [ 'es'=>'Evaluamos distintas áreas con los mismos criterios.','en'=>'We evaluate different areas using the same criteria.','fr'=>'Nous évaluons différentes zones selon les mêmes critères.','de'=>'Wir bewerten verschiedene Zonen nach denselben Kriterien.','ru'=>'Мы оцениваем разные зоны по одинаковым критериям.' ],
        'sec.i2t'             => [ 'es'=>'Análisis urbanístico','en'=>'Urban planning analysis','fr'=>'Analyse urbanistique','de'=>'Stadtplanerische Analyse','ru'=>'Анализ градостроительства' ],
        'sec.i2d'             => [ 'es'=>'Normativa local, uso del suelo y características urbanas.','en'=>'Local regulations, land use and urban characteristics.','fr'=>'Réglementation locale, utilisation des terres et caractéristiques urbaines.','de'=>'Lokale Vorschriften, Landnutzung und städtische Merkmale.','ru'=>'Местные нормативы, землепользование и городские характеристики.' ],
        'sec.i3t'             => [ 'es'=>'Entorno e infraestructura','en'=>'Environment and infrastructure','fr'=>'Environnement et infrastructure','de'=>'Umgebung und Infrastruktur','ru'=>'Окружение и инфраструктура' ],
        'sec.i3d'             => [ 'es'=>'Conectividad, servicios y calidad del entorno.','en'=>'Connectivity, services and environmental quality.','fr'=>'Connectivité, services et qualité de l\'environnement.','de'=>'Konnektivität, Dienstleistungen und Umgebungsqualität.','ru'=>'Связность, услуги и качество окружающей среды.' ],
        'sec.i4t'             => [ 'es'=>'Perfil de la demanda local','en'=>'Local demand profile','fr'=>'Profil de la demande locale','de'=>'Lokales Nachfrageprofil','ru'=>'Профиль местного спроса' ],
        'sec.i4d'             => [ 'es'=>'Quién habita y quién busca en cada zona.','en'=>'Who inhabits and who seeks in each area.','fr'=>'Qui habite et qui cherche dans chaque zone.','de'=>'Wer lebt und wer sucht in jeder Zone.','ru'=>'Кто населяет и кто ищет в каждой зоне.' ],
        'sec.inv.link'        => [ 'es'=>'Solicitar informe de zona','en'=>'Request zone report','fr'=>'Demander un rapport de zone','de'=>'Zonenbericht anfordern','ru'=>'Запросить отчёт по зоне' ],
        'sec.final.title'     => [ 'es'=>'Conocer antes de decidir es siempre la mejor estrategia.','en'=>'Knowing before deciding is always the best strategy.','fr'=>'Savoir avant de décider est toujours la meilleure stratégie.','de'=>'Zu wissen, bevor man entscheidet, ist immer die beste Strategie.','ru'=>'Знать перед принятием решения — всегда лучшая стратегия.' ],
