        // ── META DESCRIPTIONS ─────────────────────────────────────
        'meta.home.desc'      => [ 'es'=>'Romvill ofrece inteligencia territorial en la Costa Mediterránea: informes expertos sobre seguridad, demografía, sanidad y movilidad para compra, inversión o traslado.','en'=>'Romvill provides territorial intelligence on the Mediterranean Coast: expert reports on security, demographics, health and mobility for purchase, investment or relocation.','fr'=>'Romvill offre une intelligence territoriale sur la Côte Méditerranéenne : rapports d\'experts sur la sécurité, la démographie, la santé et la mobilité pour achat, investissement ou déménagement.','de'=>'Romvill bietet territoriale Intelligenz an der Mittelmeerküste: Expertenberichte über Sicherheit, Demografie, Gesundheit und Mobilität für Kauf, Investition oder Umzug.','ru'=>'Romvill предоставляет территориальную аналитику на Средиземноморском побережье: экспертные отчёты о безопасности, демографии, здравоохранении и мобильности для покупки, инвестиций или переезда.' ],
        'meta.met.desc'       => [ 'es'=>'Descubra cómo Romvill elabora sus informes: recolección OSINT, análisis de campo y presentación estructurada para que tome decisiones con criterio.','en'=>'Discover how Romvill prepares its reports: OSINT collection, field analysis and structured presentation so you make informed decisions.','fr'=>'Découvrez comment Romvill prépare ses rapports : collecte OSINT, analyse de terrain et présentation structurée pour décider en connaissance de cause.','de'=>'Erfahren Sie, wie Romvill seine Berichte erstellt: OSINT-Sammlung, Feldanalyse und strukturierte Darstellung für fundierte Entscheidungen.','ru'=>'Узнайте, как Romvill составляет свои отчёты: сбор OSINT, полевой анализ и структурированная презентация для обоснованных решений.' ],
        'meta.ana.desc'       => [ 'es'=>'Romvill analiza cuatro dimensiones clave: seguridad real, perfil demográfico, cobertura sanitaria y movilidad. Conozca la zona antes de decidir.','en'=>'Romvill analyses four key dimensions: real security, demographic profile, healthcare coverage and mobility. Know the area before you decide.','fr'=>'Romvill analyse quatre dimensions clés : sécurité réelle, profil démographique, couverture sanitaire et mobilité. Connaissez la zone avant de décider.','de'=>'Romvill analysiert vier Schlüsseldimensionen: echte Sicherheit, demografisches Profil, Gesundheitsversorgung und Mobilität. Kennen Sie die Zone, bevor Sie entscheiden.','ru'=>'Romvill анализирует четыре ключевых измерения: реальная безопасность, демографический профиль, охват здравоохранения и мобильность. Узнайте район перед принятием решения.' ],
        'meta.sec.desc'       => [ 'es'=>'Romvill trabaja con particulares, familias e inversores en Alicante, Marbella y Málaga. Estudios residenciales y análisis territorial especializado.','en'=>'Romvill works with individuals, families and investors in Alicante, Marbella and Málaga. Residential studies and specialised territorial analysis.','fr'=>'Romvill travaille avec des particuliers, des familles et des investisseurs à Alicante, Marbella et Málaga. Études résidentielles et analyses territoriales spécialisées.','de'=>'Romvill arbeitet mit Privatpersonen, Familien und Investoren in Alicante, Marbella und Málaga. Wohnstudien und spezialisierte territoriale Analysen.','ru'=>'Romvill работает с физическими лицами, семьями и инвесторами в Аликанте, Марбелье и Малаге. Жилищные исследования и специализированный территориальный анализ.' ],
        'meta.cont.desc'      => [ 'es'=>'Solicite su informe territorial personalizado. Contacte con Romvill para conocer la zona que le interesa antes de comprar, invertir o trasladarse.','en'=>'Request your personalised territorial report. Contact Romvill to learn about the area that interests you before buying, investing or relocating.','fr'=>'Demandez votre rapport territorial personnalisé. Contactez Romvill pour en savoir plus sur la zone qui vous intéresse avant d\'acheter, d\'investir ou de déménager.','de'=>'Beantragen Sie Ihren personalisierten Territorialbericht. Kontaktieren Sie Romvill, um mehr über die Sie interessierende Zone zu erfahren.','ru'=>'Запросите персонализированный территориальный отчёт. Свяжитесь с Romvill, чтобы узнать об интересующем вас районе.' ],
        'meta.priv.desc'      => [ 'es'=>'Política de privacidad de Romvill. Cómo recopilamos, usamos y protegemos su información personal de acuerdo con el RGPD.','en'=>'Romvill privacy policy. How we collect, use and protect your personal information in accordance with the GDPR.','fr'=>'Politique de confidentialité de Romvill. Comment nous collectons, utilisons et protégeons vos informations personnelles conformément au RGPD.','de'=>'Datenschutzrichtlinie von Romvill. Wie wir Ihre persönlichen Daten gemäß der DSGVO erheben, verwenden und schützen.','ru'=>'Политика конфиденциальности Romvill. Как мы собираем, используем и защищаем ваши персональные данные в соответствии с GDPR.' ],
        'meta.terms.desc'     => [ 'es'=>'Términos y condiciones de uso de Romvill. Conozca las condiciones que rigen la prestación de nuestros servicios de análisis territorial.','en'=>'Romvill terms and conditions of use. Learn about the conditions governing the provision of our territorial analysis services.','fr'=>'Conditions générales d\'utilisation de Romvill. Découvrez les conditions régissant nos services d\'analyse territoriale.','de'=>'Nutzungsbedingungen von Romvill. Erfahren Sie mehr über die Bedingungen für unsere territorialen Analysedienste.','ru'=>'Условия использования Romvill. Ознакомьтесь с условиями предоставления наших услуг территориального анализа.' ],

        // ── PRIVACIDAD PAGE ───────────────────────────────────────
        'priv.title'          => [ 'es'=>'Política de Privacidad','en'=>'Privacy Policy','fr'=>'Politique de Confidentialité','de'=>'Datenschutzrichtlinie','ru'=>'Политика Конфиденциальности' ],
        'priv.badge'          => [ 'es'=>'Legal','en'=>'Legal','fr'=>'Légal','de'=>'Rechtlich','ru'=>'Правовой' ],
        'priv.updated'        => [ 'es'=>'Última actualización: enero 2025','en'=>'Last updated: January 2025','fr'=>'Dernière mise à jour : janvier 2025','de'=>'Letzte Aktualisierung: Januar 2025','ru'=>'Последнее обновление: январь 2025' ],
        'priv.intro'          => [ 'es'=>'En Romvill respetamos su privacidad y nos comprometemos a proteger sus datos personales. Esta política describe qué información recopilamos, cómo la usamos y cuáles son sus derechos conforme al Reglamento General de Protección de Datos (RGPD).','en'=>'At Romvill we respect your privacy and are committed to protecting your personal data. This policy describes what information we collect, how we use it and what your rights are under the General Data Protection Regulation (GDPR).','fr'=>'Chez Romvill, nous respectons votre vie privée et nous nous engageons à protéger vos données personnelles. Cette politique décrit les informations que nous collectons, comment nous les utilisons et quels sont vos droits en vertu du Règlement Général sur la Protection des Données (RGPD).','de'=>'Bei Romvill respektieren wir Ihre Privatsphäre und verpflichten uns, Ihre personenbezogenen Daten zu schützen. Diese Richtlinie beschreibt, welche Informationen wir erheben, wie wir sie verwenden und welche Rechte Sie gemäß der Datenschutz-Grundverordnung (DSGVO) haben.','ru'=>'В Romvill мы уважаем вашу конфиденциальность и обязуемся защищать ваши персональные данные. Эта политика описывает, какую информацию мы собираем, как её используем и каковы ваши права в соответствии с Общим регламентом о защите данных (GDPR).' ],
        'priv.s1.title'       => [ 'es'=>'Datos que recopilamos','en'=>'Data we collect','fr'=>'Données que nous collectons','de'=>'Daten, die wir erheben','ru'=>'Данные, которые мы собираем' ],
        'priv.s1.body'        => [ 'es'=>'Cuando utiliza nuestro formulario de contacto recopilamos: nombre, apellido, dirección de correo electrónico, teléfono (opcional), zona de interés y el mensaje que nos envía. No recopilamos datos de pago ni instalamos cookies de seguimiento de terceros.','en'=>'When you use our contact form we collect: first name, last name, email address, phone (optional), area of interest and the message you send us. We do not collect payment data or install third-party tracking cookies.','fr'=>'Lorsque vous utilisez notre formulaire de contact, nous collectons : prénom, nom de famille, adresse e-mail, téléphone (facultatif), zone d\'intérêt et le message que vous nous envoyez. Nous ne collectons pas de données de paiement ni n\'installons de cookies de suivi tiers.','de'=>'Wenn Sie unser Kontaktformular nutzen, erheben wir: Vorname, Nachname, E-Mail-Adresse, Telefon (optional), Interessengebiet und die Nachricht, die Sie uns senden. Wir erheben keine Zahlungsdaten und installieren keine Tracking-Cookies von Drittanbietern.','ru'=>'При использовании контактной формы мы собираем: имя, фамилию, адрес электронной почты, телефон (необязательно), зону интереса и ваше сообщение. Мы не собираем платёжные данные и не устанавливаем сторонние cookie для отслеживания.' ],
        'priv.s2.title'       => [ 'es'=>'Cómo usamos sus datos','en'=>'How we use your data','fr'=>'Comment nous utilisons vos données','de'=>'Wie wir Ihre Daten verwenden','ru'=>'Как мы используем ваши данные' ],
        'priv.s2.body'        => [ 'es'=>'Usamos sus datos exclusivamente para responder a su solicitud de informe y gestionar la relación comercial si así lo decide. No vendemos ni cedemos sus datos a terceros. Sus datos se tratan con base en su consentimiento (Art. 6.1.a RGPD) o en la ejecución de un contrato (Art. 6.1.b RGPD). Los datos se conservan durante el tiempo estrictamente necesario para la gestión del servicio solicitado.','en'=>'We use your data exclusively to respond to your report request and manage the commercial relationship should you choose to proceed. We do not sell or share your data with third parties. Your data is processed on the basis of your consent (Art. 6.1.a GDPR) or for the performance of a contract (Art. 6.1.b GDPR). Data is retained for the time strictly necessary to manage the requested service.','fr'=>'Nous utilisons vos données exclusivement pour répondre à votre demande de rapport et gérer la relation commerciale si vous le décidez. Nous ne vendons ni ne cédons vos données à des tiers. Vos données sont traitées sur la base de votre consentement (Art. 6.1.a RGPD) ou de l\'exécution d\'un contrat (Art. 6.1.b RGPD). Les données sont conservées pendant le temps strictement nécessaire à la gestion du service demandé.','de'=>'Wir verwenden Ihre Daten ausschließlich zur Beantwortung Ihrer Berichtsanfrage und zur Verwaltung der Geschäftsbeziehung, sofern Sie dies entscheiden. Wir verkaufen oder übermitteln Ihre Daten nicht an Dritte. Ihre Daten werden auf Grundlage Ihrer Einwilligung (Art. 6.1.a DSGVO) oder der Vertragserfüllung (Art. 6.1.b DSGVO) verarbeitet.','ru'=>'Мы используем ваши данные исключительно для ответа на запрос отчёта и управления деловыми отношениями. Мы не продаём и не передаём ваши данные третьим лицам. Обработка осуществляется на основании вашего согласия (ст. 6.1.a GDPR) или исполнения договора (ст. 6.1.b GDPR).' ],
        'priv.s3.title'       => [ 'es'=>'Sus derechos','en'=>'Your rights','fr'=>'Vos droits','de'=>'Ihre Rechte','ru'=>'Ваши права' ],
        'priv.s3.body'        => [ 'es'=>'Conforme al RGPD, tiene derecho a acceder, rectificar, suprimir, limitar el tratamiento, portabilidad y oponerse al tratamiento de sus datos. Para ejercer cualquiera de estos derechos, escríbanos a info@romvill.com con el asunto "Derechos RGPD". También puede presentar una reclamación ante la Agencia Española de Protección de Datos (aepd.es).','en'=>'Under the GDPR, you have the right to access, rectify, erase, restrict processing, data portability and to object to the processing of your data. To exercise any of these rights, write to us at info@romvill.com with the subject "GDPR Rights". You may also lodge a complaint with your national data protection authority.','fr'=>'Conformément au RGPD, vous avez le droit d\'accéder, de rectifier, de supprimer, de limiter le traitement, à la portabilité et de vous opposer au traitement de vos données. Pour exercer l\'un de ces droits, écrivez-nous à info@romvill.com avec l\'objet "Droits RGPD".','de'=>'Gemäß DSGVO haben Sie das Recht auf Zugang, Berichtigung, Löschung, Einschränkung der Verarbeitung, Datenübertragbarkeit und Widerspruch. Um diese Rechte auszuüben, schreiben Sie uns an info@romvill.com mit dem Betreff "DSGVO-Rechte".','ru'=>'В соответствии с GDPR вы имеете право на доступ, исправление, удаление, ограничение обработки, переносимость данных и возражение. Для реализации прав напишите на info@romvill.com с темой «Права GDPR».' ],
        'priv.s4.title'       => [ 'es'=>'Responsable del tratamiento','en'=>'Data controller','fr'=>'Responsable du traitement','de'=>'Verantwortlicher','ru'=>'Ответственный за обработку' ],
        'priv.s4.body'        => [ 'es'=>'Responsable: Romvill. Correo de contacto: info@romvill.com. Domicilio social: España. Si tiene cualquier duda sobre el tratamiento de sus datos, no dude en contactarnos.','en'=>'Controller: Romvill. Contact email: info@romvill.com. Registered address: Spain. If you have any questions about the processing of your data, please do not hesitate to contact us.','fr'=>'Responsable : Romvill. E-mail de contact : info@romvill.com. Siège social : Espagne. Si vous avez des questions sur le traitement de vos données, n\'hésitez pas à nous contacter.','de'=>'Verantwortlicher: Romvill. Kontakt-E-Mail: info@romvill.com. Sitz: Spanien. Wenn Sie Fragen zur Verarbeitung Ihrer Daten haben, zögern Sie nicht, uns zu kontaktieren.','ru'=>'Ответственный: Romvill. Email: info@romvill.com. Адрес: Испания. По любым вопросам обработки данных обращайтесь к нам.' ],

        // ── TÉRMINOS PAGE ─────────────────────────────────────────
        'terms.title'         => [ 'es'=>'Términos y Condiciones','en'=>'Terms and Conditions','fr'=>'Conditions Générales','de'=>'Nutzungsbedingungen','ru'=>'Условия Использования' ],
        'terms.badge'         => [ 'es'=>'Legal','en'=>'Legal','fr'=>'Légal','de'=>'Rechtlich','ru'=>'Правовой' ],
        'terms.updated'       => [ 'es'=>'Última actualización: enero 2025','en'=>'Last updated: January 2025','fr'=>'Dernière mise à jour : janvier 2025','de'=>'Letzte Aktualisierung: Januar 2025','ru'=>'Последнее обновление: январь 2025' ],
        'terms.intro'         => [ 'es'=>'Al acceder o utilizar el sitio web de Romvill y solicitar nuestros servicios, usted acepta los presentes términos y condiciones. Si no está de acuerdo con alguno de ellos, le rogamos que no utilice el servicio.','en'=>'By accessing or using the Romvill website and requesting our services, you accept these terms and conditions. If you do not agree with any of them, please do not use the service.','fr'=>'En accédant au site web de Romvill et en demandant nos services, vous acceptez les présentes conditions générales. Si vous n\'êtes pas d\'accord, nous vous prions de ne pas utiliser le service.','de'=>'Durch den Zugriff auf die Romvill-Website und die Inanspruchnahme unserer Dienste akzeptieren Sie diese Nutzungsbedingungen. Wenn Sie nicht einverstanden sind, bitten wir Sie, den Dienst nicht zu nutzen.','ru'=>'Получая доступ к сайту Romvill и запрашивая наши услуги, вы принимаете настоящие условия использования. Если вы не согласны — просим не пользоваться сервисом.' ],
        'terms.s1.title'      => [ 'es'=>'Descripción del servicio','en'=>'Service description','fr'=>'Description du service','de'=>'Dienstbeschreibung','ru'=>'Описание услуги' ],
        'terms.s1.body'       => [ 'es'=>'Romvill presta servicios de análisis e inteligencia territorial en la Costa Mediterránea española. Los informes son documentos informativos y no constituyen asesoramiento legal, financiero o inmobiliario vinculante. Cada informe se elabora de forma personalizada bajo los criterios profesionales del equipo Romvill y se entrega en el plazo acordado con el cliente.','en'=>'Romvill provides territorial analysis and intelligence services on the Spanish Mediterranean Coast. The reports are informational documents and do not constitute binding legal, financial or real estate advice. Each report is prepared on a personalised basis under the professional criteria of the Romvill team and delivered within the timeframe agreed with the client.','fr'=>'Romvill fournit des services d\'analyse et d\'intelligence territoriale sur la Côte Méditerranéenne espagnole. Les rapports sont des documents d\'information et ne constituent pas un conseil contraignant. Chaque rapport est préparé de façon personnalisée et livré dans le délai convenu.','de'=>'Romvill bietet territoriale Analyse- und Intelligenzdienstleistungen an der spanischen Mittelmeerküste an. Die Berichte sind Informationsdokumente und keine verbindliche Beratung. Jeder Bericht wird personalisiert und innerhalb der vereinbarten Frist geliefert.','ru'=>'Romvill предоставляет услуги территориального анализа на испанском средиземноморском побережье. Отчёты являются информационными документами и не являются обязывающими советами. Каждый отчёт готовится индивидуально в согласованные сроки.' ],
        'terms.s2.title'      => [ 'es'=>'Limitación de responsabilidad','en'=>'Limitation of liability','fr'=>'Limitation de responsabilité','de'=>'Haftungsbeschränkung','ru'=>'Ограничение ответственности' ],
        'terms.s2.body'       => [ 'es'=>'Romvill no garantiza que los datos incluidos en el informe sean exhaustivos o completamente actualizados en el momento de su entrega. La información proporcionada no debe usarse como único criterio para tomar decisiones de compra, inversión o traslado. Romvill no se hace responsable de las decisiones tomadas basándose en los informes ni de los daños y perjuicios que pudieran derivarse.','en'=>'Romvill does not guarantee that the data included in the report is exhaustive or fully up-to-date at the time of delivery. The information should not be used as the sole criterion for purchase, investment or relocation decisions. Romvill is not responsible for decisions made based on the reports nor for any resulting damages.','fr'=>'Romvill ne garantit pas que les données sont exhaustives ou entièrement à jour. Les informations fournies ne doivent pas être utilisées comme seul critère décisionnel. Romvill n\'est pas responsable des décisions prises sur la base des rapports.','de'=>'Romvill garantiert nicht, dass die Berichtsdaten vollständig oder aktuell sind. Die Informationen sollten nicht als alleiniges Entscheidungskriterium genutzt werden. Romvill übernimmt keine Haftung für auf Basis der Berichte getroffene Entscheidungen.','ru'=>'Romvill не гарантирует исчерпывающей актуальности данных на момент доставки. Информация не должна использоваться как единственный критерий решения. Romvill не несёт ответственности за решения на основе отчётов.' ],
        'terms.s3.title'      => [ 'es'=>'Propiedad intelectual','en'=>'Intellectual property','fr'=>'Propriété intellectuelle','de'=>'Geistiges Eigentum','ru'=>'Интеллектуальная собственность' ],
        'terms.s3.body'       => [ 'es'=>'Todos los informes, metodologías y contenidos del sitio web son propiedad intelectual de Romvill. Queda prohibida su reproducción total o parcial sin autorización escrita. El cliente puede usar el informe para uso personal o interno de su empresa, pero no para redistribución comercial ni publicación sin consentimiento.','en'=>'All reports, methodologies and website content are the intellectual property of Romvill. Their total or partial reproduction without written authorisation is prohibited. The client may use the report for personal or internal business use, but not for commercial redistribution or publication without consent.','fr'=>'Tous les rapports, méthodologies et contenus sont la propriété intellectuelle de Romvill. Leur reproduction sans autorisation écrite est interdite. Le client peut utiliser le rapport à des fins personnelles, mais non pour la redistribution commerciale.','de'=>'Alle Berichte, Methoden und Website-Inhalte sind geistiges Eigentum von Romvill. Reproduktion ohne schriftliche Genehmigung ist verboten. Der Kunde darf den Bericht für persönliche Zwecke nutzen, nicht zur kommerziellen Weitergabe.','ru'=>'Все отчёты, методологии и контент являются интеллектуальной собственностью Romvill. Воспроизведение без письменного разрешения запрещено. Клиент может использовать отчёт в личных целях, но не для коммерческого распространения.' ],
        'terms.s4.title'      => [ 'es'=>'Ley aplicable','en'=>'Governing law','fr'=>'Loi applicable','de'=>'Anwendbares Recht','ru'=>'Применимое право' ],
        'terms.s4.body'       => [ 'es'=>'Estos términos se rigen por la legislación española. Cualquier disputa que surja será sometida a los tribunales de la ciudad de Alicante, salvo que la normativa de protección al consumidor aplicable establezca otro fuero competente.','en'=>'These terms are governed by Spanish law. Any dispute arising will be submitted to the courts of the city of Alicante, unless applicable consumer protection regulations provide for a different jurisdiction.','fr'=>'Ces conditions sont régies par le droit espagnol. Tout litige sera soumis aux tribunaux d\'Alicante, sauf disposition contraire de la réglementation applicable sur la protection des consommateurs.','de'=>'Diese Bedingungen unterliegen dem spanischen Recht. Streitigkeiten werden den Gerichten der Stadt Alicante vorgelegt, sofern das Verbraucherschutzrecht nichts anderes vorsieht.','ru'=>'Условия регулируются испанским законодательством. Споры передаются в суды Аликанте, если только применимое законодательство о защите прав потребителей не предусматривает иного.' ],
    ];
}
